func CanSum(arr []int, target int) int {
	if target == 0 {
		return 1
	}

	dp := make([]bool, target+1)
	dp[0] = true

	for i := 1; i <= target; i++ {
		for _, elem := range arr {
			if elem <= i && dp[i-elem] {
				dp[i] = true
				break
			}
		}
	}

	if dp[target] {
		return 1
	}
	return 0
